import json
import pandas as pd

# ---- Field mapping (variant name -> unified name) ----
FIELD_MAP = {
    "user_id": "user_id", "id": "user_id", "userId": "user_id",
    "email": "email", "email_address": "email",
    "full_name": "name", "name": "name", "userName": "name",
    "registration_date": "created_date", "created_at": "created_date", "joined": "created_date",
    # status variants
    "status": "status", "is_active": "status", "active": "status",
}


def norm_date(v):
    if v is None or (isinstance(v, float) and pd.isna(v)):
        return None
    return pd.to_datetime(v).strftime("%Y-%m-%d")


def norm_status(v):
    if v is None or (isinstance(v, float) and pd.isna(v)):
        return None
    if isinstance(v, bool):
        return "active" if v else "inactive"
    s = str(v).strip()
    if s.lower() in ("true", "false"):
        return "active" if s.lower() == "true" else "inactive"
    return s


def remap(record):
    out = {}
    for k, v in record.items():
        uk = FIELD_MAP.get(k)
        if uk is None:
            continue
        out[uk] = v
    if "user_id" in out and out["user_id"] is not None:
        out["user_id"] = int(out["user_id"])
    if "created_date" in out:
        out["created_date"] = norm_date(out["created_date"])
    if "status" in out:
        out["status"] = norm_status(out["status"])
    return out


# ---- Load sources ----
with open("/data/source_a/users.json") as f:
    src_a = [remap(r) for r in json.load(f)]

df_b = pd.read_csv("/data/source_b/users.csv")
src_b = [remap(r) for r in df_b.to_dict(orient="records")]

df_c = pd.read_parquet("/data/source_c/users.parquet")
src_c = [remap(r) for r in df_c.to_dict(orient="records")]

sources = {"source_a": src_a, "source_b": src_b, "source_c": src_c}
PRIORITY = ["source_a", "source_b", "source_c"]  # highest -> lowest

# index records by user_id per source
by_id = {}
for sname, recs in sources.items():
    for r in recs:
        uid = r.get("user_id")
        if uid is None:
            continue
        by_id.setdefault(uid, {})[sname] = r

CONFLICT_FIELDS = ["name", "email", "created_date", "status"]

merged = []
conflicts = []

for uid in sorted(by_id):
    per_source = by_id[uid]
    record = {"user_id": uid}

    # resolve each field by priority
    for field in CONFLICT_FIELDS:
        chosen = None
        for sname in PRIORITY:
            r = per_source.get(sname)
            if r is not None and r.get(field) is not None:
                chosen = r.get(field)
                break
        record[field] = chosen

        # conflict detection: differing non-null values across sources
        present = {}
        for sname in PRIORITY:
            r = per_source.get(sname)
            if r is not None and field in r and r.get(field) is not None:
                present[sname] = r.get(field)
        if len(set(present.values())) > 1:
            conflicts.append({
                "user_id": uid,
                "field": field,
                "values": {s: present[s] for s in PRIORITY if s in present},
                "selected": chosen,
            })

    merged.append(record)

# ---- Write merged parquet ----
out_df = pd.DataFrame(merged, columns=["user_id", "name", "email", "created_date", "status"])
out_df["user_id"] = out_df["user_id"].astype("int64")
for col in ["name", "email", "created_date", "status"]:
    out_df[col] = out_df[col].astype("object")
out_df.to_parquet("/app/merged_users.parquet", index=False)

# ---- Write conflict report ----
report = {"total_conflicts": len(conflicts), "conflicts": conflicts}
with open("/app/conflicts.json", "w") as f:
    json.dump(report, f, indent=2)

print(out_df.to_string())
print(json.dumps(report, indent=2))

